#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[15];
	int ke;
	double wendu;
};
student a[110];
int n,cnt=0;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%s",a[i].name);
		scanf("%lf%d",&(a[i].wendu),&(a[i].ke));
	}
	for(int j=1;j<=n;j++)
	{
		if(a[j].ke==1&&a[j].wendu>=37.5)
		{
			printf("%s\n",a[j].name);
			cnt++;
		}
	}
	printf("%d",cnt);
	return 0;
}
